import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

const PHOTO_B64 = "";
const ITEM_ID = 12;
const STALE_ITEM_ID = 4;

Deno.serve(async () => {
  const supabase = createClient(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!,
  );

  const bin = Uint8Array.from(atob(PHOTO_B64), c => c.charCodeAt(0));

  const { data: machines, error: mErr } = await supabase.from("machines").select("id");
  if (mErr) return new Response(JSON.stringify({ error: mErr.message }), { status: 500 });

  const results: any[] = [];
  for (const m of machines ?? []) {
    const newPath = `${m.id}/${ITEM_ID}.jpg`;
    const stalePath = `${m.id}/${STALE_ITEM_ID}.jpg`;

    const up = await supabase.storage.from("reference-photos").upload(newPath, bin, {
      upsert: true, contentType: "image/jpeg",
    });
    if (up.error) { results.push({ m: m.id, step: "upload", err: up.error.message }); continue; }

    const ups = await supabase.from("machine_reference_photos").upsert({
      machine_id: m.id, item_id: ITEM_ID, path: newPath, updated_at: new Date().toISOString(),
    }, { onConflict: "machine_id,item_id" });
    if (ups.error) { results.push({ m: m.id, step: "upsert", err: ups.error.message }); continue; }

    // Cleanup stale row + file for old item_id=4
    await supabase.from("machine_reference_photos").delete().eq("machine_id", m.id).eq("item_id", STALE_ITEM_ID);
    await supabase.storage.from("reference-photos").remove([stalePath]);

    results.push({ m: m.id, ok: true });
  }

  return new Response(JSON.stringify({ results }), { headers: { "Content-Type": "application/json" } });
});
